PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE def (id INTEGER PRIMARY KEY, name TEXT NOT NULL, kind TEXT NOT NULL CHECK(kind IN ('fn','type','trait','impl','const','fsm','srv','macro','test')), sig TEXT, body TEXT NOT NULL, hash BLOB NOT NULL, tokens INTEGER NOT NULL, compiled INTEGER NOT NULL DEFAULT 0, created TEXT NOT NULL DEFAULT (datetime('now')), modified TEXT NOT NULL DEFAULT (datetime('now')));
CREATE TABLE dep (from_id INTEGER NOT NULL REFERENCES def(id) ON DELETE CASCADE, to_id INTEGER NOT NULL REFERENCES def(id) ON DELETE CASCADE, edge TEXT NOT NULL CHECK(edge IN ('calls','uses_type','implements','field_of','variant_of')), PRIMARY KEY (from_id, to_id, edge));
CREATE TABLE extern_ (id INTEGER PRIMARY KEY, name TEXT NOT NULL, symbol TEXT NOT NULL, lib TEXT, sig TEXT NOT NULL, conv TEXT NOT NULL DEFAULT 'C' CHECK(conv IN ('C','system','rust')), UNIQUE(name));
CREATE TABLE tag (def_id INTEGER NOT NULL REFERENCES def(id) ON DELETE CASCADE, key TEXT NOT NULL, val TEXT, PRIMARY KEY (def_id, key));
CREATE TABLE module (id INTEGER PRIMARY KEY, name TEXT NOT NULL UNIQUE, doc TEXT);
CREATE TABLE module_member (module_id INTEGER NOT NULL REFERENCES module(id) ON DELETE CASCADE, def_id INTEGER NOT NULL REFERENCES def(id) ON DELETE CASCADE, exported INTEGER NOT NULL DEFAULT 1, PRIMARY KEY (module_id, def_id));
CREATE TABLE compiled (def_id INTEGER PRIMARY KEY REFERENCES def(id) ON DELETE CASCADE, ir BLOB NOT NULL, target TEXT NOT NULL, hash BLOB NOT NULL);
CREATE TABLE meta (key TEXT PRIMARY KEY, val TEXT NOT NULL);
CREATE VIEW v_dirty AS WITH RECURSIVE dirty(id) AS (SELECT id FROM def WHERE compiled = 0 UNION SELECT d.from_id FROM dep d JOIN dirty ON d.to_id = dirty.id) SELECT DISTINCT def.* FROM def JOIN dirty ON def.id = dirty.id;
CREATE VIEW v_context AS SELECT d.*, COUNT(dep.to_id) as dep_count FROM def d LEFT JOIN dep ON d.id = dep.from_id GROUP BY d.id ORDER BY dep_count ASC, d.tokens ASC;
CREATE VIEW v_callgraph AS SELECT f.name AS caller, t.name AS callee, d.edge FROM dep d JOIN def f ON d.from_id = f.id JOIN def t ON d.to_id = t.id;
CREATE UNIQUE INDEX idx_def_name_kind ON def(name, kind);
CREATE INDEX idx_def_kind ON def(kind);
CREATE INDEX idx_def_compiled ON def(compiled) WHERE compiled = 0;
CREATE INDEX idx_dep_to ON dep(to_id);
CREATE INDEX idx_tag_key_val ON tag(key, val);
COMMIT;
